import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.encoder.Encode;

public class XSSSafeServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");
        String safeInput = Encode.forHtml(userInput); // Encode user input to prevent XSS

        out.println("<html><head><title>XSS Safe Page</title></head><body>");
        out.println("<h1>Welcome " + safeInput + "!</h1>");
        out.println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
